var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배!","JPN":"先輩！","ENG":"Shiyoon!","TWN":"前輩！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 정신차려! 선배!!","JPN":"先輩、しっかりして！　先輩！！","ENG":"Wake up! Shiyoon!!","TWN":"前輩！你振作一點！！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미…… 미나 양……?","JPN":"ミ……ミナさん……？","ENG":"M-Mina?","TWN":"米……米娜……？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다행이다. 무사해서.","JPN":"よかった。無事だったのね。","ENG":"Thank goodness. You're all right!","TWN":"幸好你沒事！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"조금만 기다려. 내가 풀어 줄게.","JPN":"少しだけ待ってて。私が解いてあげる。","ENG":"Give me just a second. I'll untie you.","TWN":"等一下，我現在就替你鬆綁！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 사람은…… 여기 다른 사람은 없었나요?","JPN":"他の人は……ここに他の人はいませんでした？","ENG":"Did you see… anyone else here?","TWN":"其他人呢……這裡沒有其他人嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다른 사람? 선배 말고 또 누가 갇혀 있던 거야?","JPN":"他の人？　先輩以外に他の人が閉じ込められていたの？","ENG":"Someone else? Was there someone else locked up in here?","TWN":"其他人？除了前輩還有其他人被關在這裡嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 왔을 때는 선배밖에 없었어.","JPN":"私が着いた時は先輩しかいなかったよ。","ENG":"I didn't see anyone but you when I got here.","TWN":"我來的時候只有看到前輩而已。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"혹시 납치범이나 그 일당들을 말하는 거야?","JPN":"もしかして誘拐犯とかその一味のこと？","ENG":"Are you talking about the guys who abducted you?","TWN":"還是你是指綁架你的人跟他的同夥？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러고 보니 궁금한 게 있는데…… 선배를 습격한 게 정말 레이 선배였어?","JPN":"そういえば気になることがあるんだけど……先輩を襲ったのは本当にレイ先輩だったの？","ENG":"Which reminds me… Was it really Ray who ambushed you?","TWN":"說到這個，我想知道……偷襲前輩的人真的是雷伊前輩嗎？　"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 왜 레이 선배가 이런 짓을 저지른 거야?","JPN":"いったいなんでレイ先輩はこんなことをしたの？","ENG":"Why would Ray do such a thing?","TWN":"雷伊前輩為什麼要這麼做?　"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 알렌 선생님은? 그 사람도 이 일에 관련되어 있는 거야?","JPN":"あとアレン先生は？　あの人もこの事件に関係してるの？","ENG":"And what about Mr. Birmingham? Is he tied up in this as well?","TWN":"還有艾倫老師，他也和這件事有關嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……미안해요. 지금은 자세히 대답드리기가 어렵겠네요.","JPN":"……すみません、今詳しく答えるのはちょっと難しいですね。","ENG":"…Sorry. I'm not sure I can give you answers right now.","TWN":"……不好意思，我現在無法回答這麼多問題。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"피를 많이 흘렸더니, 조금 어지러워서…….","JPN":"血を流しすぎて、少し目まいが……","ENG":"I'm pretty dizzy from the blood loss…","TWN":"我血流太多，現在頭有點暈……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"미, 미안. 선배도 몸이 정상은 아닐 텐데…….","JPN":"ご、ごめん。先輩も辛い状況なのに……","ENG":"S-sorry. It must be rough for you…","TWN":"對…對不起！都忘記你現在是傷患……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"일단은 안전한 곳으로 가자. 걸을 수 있겠어?","JPN":"とりあえず安全な場所に行こう。歩けそう？","ENG":"Let's get you somewhere safe first. Think you can walk?","TWN":"我們先移動到安全的地方吧？你還能走嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……하하, 쉽진 않네요.","JPN":"……ハハ、厳しそうです。","ENG":"Haha… I'm not so sure about that.","TWN":"……哈哈，有點難。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"오랫동안 묶여 있어서 그런가 보네.","JPN":"長い間縛られていたせいだね。","ENG":"I guess you've been tied up for too long.","TWN":"可能是因為身體長時間被綁住，才會腳麻不能動。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};